namespace highspeed.framework.Common
{
    public class AsposeHelper
    {
        private const string asposeKey = "";

        public static void SetupLicense()
        {
            var byteKey = Convert.FromBase64String(asposeKey);
            new Aspose.Words.License().SetLicense(new MemoryStream(byteKey));
            new Aspose.Cells.License().SetLicense(new MemoryStream(byteKey));
        }
    }
}
